 <aside class="panel"><h2>Меню</h2><div class="menu-list"><?php foreach($menus as $menu):?><a class="<?=(int)$menu['id']===$menuId?'active':''?>" href="<?=e(app_url('/studio/menus?menu='.(int)$menu['id']))?>"><b><?=e($menu['name'])?></b><small><?=e($menu['location']??'Без позиции')?></small></a><?php endforeach;?></div><hr><form method="post" action="<?=e(app_url('/studio/menus/create'))?>"><?=csrf_field()?><div class="field"><label>Название нового меню</label><input name="name" required></div><div class="field"><label>Позиция</label><select name="location"><option value="">Не назначать</option><option value="header">Шапка</option><option value="footer">Подвал</option></select></div><button class="button primary small">Создать меню</button></form></aside>
 <section class="panel"><h2>Пункты выбранного меню</h2><?php if($menuId):?><div><?php foreach($items as $item):?><article class="menu-item-row"><div><b><?=e($item['label'])?></b><small><?=e($item['url']??'')?> · порядок <?=(int)$item['sort_order']?></small></div><form method="post" data-confirm="Удалить пункт меню?" action="<?=e(app_url('/studio/menus/item/'.(int)$item['id'].'/delete'))?>"><?=csrf_field()?><button class="button small danger">Удалить</button></form></article><?php endforeach;?><?php if(!$items):?><div class="empty-state">В меню ещё нет пунктов.</div><?php endif;?></div><hr><h3>Добавить пункт</h3><form method="post" action="<?=e(app_url('/studio/menus/item'))?>"><?=csrf_field()?><input type="hidden" name="menu_id" value="<?=$menuId?>"><div class="form-grid"><div class="field"><label>Подпись</label><input name="label" required></div><div class="field"><label>Порядок</label><input type="number" name="sort_order" value="0"></div></div><div class="field"><label>Готовая страница</label><select name="target_id"><option value="0">Своя ссылка</option><?php foreach($pages as $page):?><option value="<?=(int)$page['id']?>"><?=e($page['type'].' — '.$page['title'])?></option><?php endforeach;?></select></div><div class="field"><label>Или URL</label><input name="url" placeholder="/blog или https://..."></div><button class="button primary">Добавить пункт</button></form><?php else:?><div class="empty-state">Создайте или выберите меню слева.</div><?php endif;?></section>
